/**
 * @module app.js
 * @description Express application factory for SHOPAHOLIC API.
 * Sets up global middleware, mounts all API routes, and registers the global error handler.
 * Separated from server.js to make unit testing easier.
 */

'use strict';

require('dotenv').config();

const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const ApiError = require('./utils/apiError');

// ΓöÇΓöÇ Route modules ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const authRoutes    = require('./routes/auth');
const productRoutes = require('./routes/products');
const orderRoutes   = require('./routes/orders');

const app = express();

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// 1. Security Headers (helmet)
//    Sets sane HTTP headers to protect against XSS, clickjacking, MIME sniffing, etc.
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
app.use(helmet());

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// 2. CORS
//    Only allow requests from the configured origin(s).
//    In production: set CORS_ORIGIN to your actual frontend domain.
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const allowedOrigins = (process.env.CORS_ORIGIN || 'http://localhost:3000')
  .split(',')
  .map((o) => o.trim());

app.use(
  cors({
    origin: (origin, callback) => {
      // Allow server-to-server calls (no origin) and configured origins
      if (!origin || allowedOrigins.includes(origin)) {
        callback(null, true);
      } else {
        callback(new Error(`CORS: Origin "${origin}" is not allowed.`));
      }
    },
    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization'],
    credentials: true,
  })
);

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// 3. Body Parsers
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// 4. Request Logger (development only)
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
if (process.env.NODE_ENV !== 'production') {
  app.use((req, _res, next) => {
    console.log(`[${new Date().toISOString()}] ${req.method} ${req.url}`);
    next();
  });
}

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// 5. API Routes
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
app.use('/api/auth',     authRoutes);
app.use('/api/products', productRoutes);
app.use('/api/orders',   orderRoutes);

// Health-check endpoint ΓÇö useful for uptime monitoring
app.get('/api/health', (_req, res) => {
  res.json({ status: 'ok', service: 'SHOPAHOLIC API', timestamp: new Date().toISOString() });
});

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// 6. 404 handler ΓÇö catches any route not matched above
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
app.use((req, _res, next) => {
  next(new ApiError(404, `Cannot ${req.method} ${req.url}`));
});

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// 7. Global Error Handler
//    All controllers/middleware call next(err) to reach here.
//    Returns standardized JSON error responses.
//    Never leaks stack traces in production.
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
app.use((err, _req, res, _next) => {
  const statusCode = err.statusCode || 500;
  const message    = err.message    || 'An unexpected error occurred.';

  if (process.env.NODE_ENV !== 'production') {
    console.error('[Error]', err.stack || err);
  }

  res.status(statusCode).json({
    error: {
      status:  statusCode,
      message,
      ...(err.details && { details: err.details }),
    },
  });
});

module.exports = app;

const prisma = require('./prisma/client');

async function main() {
  console.log('≡ƒº╣ Starting Database Cleanup...');

  try {
    // Delete in order to respect foreign key constraints
    console.log('- Clearing OrderItems...');
    await prisma.orderItem.deleteMany();

    console.log('- Clearing Orders...');
    await prisma.order.deleteMany();

    console.log('- Clearing Products...');
    await prisma.product.deleteMany();

    console.log('- Clearing Categories...');
    await prisma.category.deleteMany();

    console.log('- Clearing Users...');
    await prisma.user.deleteMany();

    console.log('Γ£à Database is now CLEAN.');
  } catch (error) {
    console.error('Γ¥î Cleanup failed:', error);
  } finally {
    await prisma.$disconnect();
  }
}

main();

/**
 * @module controllers/authController.js
 * @description Handles user registration and login.
 * Passwords are hashed with bcrypt (12 salt rounds).
 * JWTs are signed with the JWT_SECRET env variable.
 * Uses Prisma ORM for all database operations.
 */

'use strict';

const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const prisma = require('../prisma/client');
const ApiError = require('../utils/apiError');

/**
 * Signs a JWT for the given user payload.
 * @param {{ id: string, email: string, role: string }} user
 * @returns {string} signed JWT
 */
const signToken = (user) =>
  jwt.sign(
    { id: user.id, email: user.email, role: user.role },
    process.env.JWT_SECRET,
    { expiresIn: process.env.JWT_EXPIRES_IN || '7d' }
  );

// ΓöÇΓöÇ POST /api/auth/register ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Register a new customer account.
 * Body: { firstName, lastName, email, password }
 * Returns: { token, user: { id, firstName, lastName, email, role } }
 */
const register = async (req, res, next) => {
  try {
    const { firstName, lastName, email, password } = req.body;

    // 1. Validate required fields
    if (!firstName || !lastName || !email || !password) {
      throw new ApiError(400, 'firstName, lastName, email and password are all required.');
    }
    if (password.length < 8) {
      throw new ApiError(400, 'Password must be at least 8 characters long.');
    }

    // 2. Ensure email is not already taken
    const existing = await prisma.user.findUnique({
      where: { email: email.toLowerCase().trim() },
      select: { id: true },
    });
    if (existing) {
      throw new ApiError(409, 'An account with this email already exists.');
    }

    // 3. Hash the password (12 rounds Γëê 250 ms ΓÇö good balance of cost vs speed)
    const passwordHash = await bcrypt.hash(password, 12);

    // 4. Create the user (role defaults to CUSTOMER per schema)
    const user = await prisma.user.create({
      data: {
        firstName: firstName.trim(),
        lastName: lastName.trim(),
        email: email.toLowerCase().trim(),
        passwordHash,
      },
      select: {
        id: true,
        firstName: true,
        lastName: true,
        email: true,
        role: true,
        createdAt: true,
      },
    });

    // 5. Sign and return the JWT
    const token = signToken(user);
    res.status(201).json({
      message: 'Account created successfully.',
      token,
      user: {
        id: user.id,
        firstName: user.firstName,
        lastName: user.lastName,
        email: user.email,
        role: user.role,
      },
    });
  } catch (err) {
    next(err);
  }
};

// ΓöÇΓöÇ POST /api/auth/login ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Log in with email and password.
 * Body: { email, password }
 * Returns: { token, user: { id, firstName, lastName, email, role } }
 */
const login = async (req, res, next) => {
  try {
    const { email, password } = req.body;

    // 1. Validate input
    if (!email || !password) {
      throw new ApiError(400, 'Email and password are required.');
    }

    // 2. Fetch user by email
    const user = await prisma.user.findUnique({
      where: { email: email.toLowerCase().trim() },
    });

    // 3. Compare password against stored bcrypt hash
    //    Generic error to avoid user enumeration
    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      throw new ApiError(401, 'Invalid email or password.');
    }

    // 4. Sign and return the JWT
    const token = signToken(user);
    res.json({
      message: 'Login successful.',
      token,
      user: {
        id: user.id,
        firstName: user.firstName,
        lastName: user.lastName,
        email: user.email,
        role: user.role,
      },
    });
  } catch (err) {
    next(err);
  }
};

// ΓöÇΓöÇ GET /api/auth/me ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Return the currently authenticated user's profile.
 * Protected ΓÇö requires authMiddleware.
 */
const getMe = async (req, res, next) => {
  try {
    const user = await prisma.user.findUnique({
      where: { id: req.user.id },
      select: {
        id: true,
        firstName: true,
        lastName: true,
        email: true,
        role: true,
        createdAt: true,
      },
    });
    if (!user) throw new ApiError(404, 'User not found.');
    res.json({ user });
  } catch (err) {
    next(err);
  }
};

module.exports = { register, login, getMe };

/**
 * @module controllers/orderController.js
 * @description Handles order creation and retrieval.
 *
 * Security: totals are ALWAYS re-calculated server-side from DB prices.
 * A malicious client cannot manipulate the amount by editing the cart payload.
 *
 * Flow (createOrder):
 *   1. Validate the incoming items array
 *   2. Fetch real prices + stock from the database
 *   3. Validate stock availability
 *   4. Calculate totalAmount server-side
 *   5. Create Order + OrderItems + decrement stock in a single Prisma transaction
 *   6. Return the order summary
 */

'use strict';

const prisma = require('../prisma/client');
const ApiError = require('../utils/apiError');

// ΓöÇΓöÇ POST /api/orders ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const createOrder = async (req, res, next) => {
  try {
    const { items, shippingAddress } = req.body;
    const userId = req.user.id; // injected by authMiddleware

    // 1. Validate input ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (!Array.isArray(items) || items.length === 0) {
      throw new ApiError(400, 'Order must include at least one item.');
    }

    for (const item of items) {
      if (
        !item.productId ||
        !Number.isInteger(item.quantity) ||
        item.quantity < 1
      ) {
        throw new ApiError(
          400,
          'Each item must have a productId and a positive integer quantity.'
        );
      }
    }

    // 2. De-duplicate product IDs
    const productIds = [...new Set(items.map((i) => i.productId))];

    // 3. Fetch real prices + stock from DB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const dbProducts = await prisma.product.findMany({
      where: { id: { in: productIds } },
      select: { id: true, title: true, price: true, stockQuantity: true },
    });

    const productMap = Object.fromEntries(dbProducts.map((p) => [p.id, p]));

    // 4. Validate stock and build line items ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    let totalAmount = 0;
    const lineItems = [];

    for (const item of items) {
      const dbProduct = productMap[item.productId];

      if (!dbProduct) {
        throw new ApiError(404, `Product "${item.productId}" not found.`);
      }
      if (dbProduct.stockQuantity < item.quantity) {
        throw new ApiError(
          422,
          `Insufficient stock for "${dbProduct.title}". Available: ${dbProduct.stockQuantity}.`
        );
      }

      const unitPrice = Number(dbProduct.price);
      totalAmount += unitPrice * item.quantity;

      lineItems.push({
        productId: dbProduct.id,
        quantity: item.quantity,
        priceAtPurchase: unitPrice,
        selectedSize: item.selectedSize || null,
        selectedColor: item.selectedColor || null,
      });
    }

    totalAmount = parseFloat(totalAmount.toFixed(2));

    // 5. Persist everything in a Prisma transaction ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const order = await prisma.$transaction(async (tx) => {
      // 5a. Create the order
      const newOrder = await tx.order.create({
        data: {
          userId,
          totalAmount,
          status: 'PENDING',
          shippingAddress: shippingAddress || {},
          items: {
            create: lineItems,
          },
        },
        include: {
          items: {
            include: {
              product: {
                select: { id: true, title: true, sku: true },
              },
            },
          },
        },
      });

      // 5b. Decrement stock for each product
      for (const li of lineItems) {
        await tx.product.update({
          where: { id: li.productId },
          data: { stockQuantity: { decrement: li.quantity } },
        });
      }

      return newOrder;
    });

    // 6. Respond ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    res.status(201).json({
      message: 'Order created successfully.',
      order: {
        id: order.id,
        status: order.status,
        totalAmount: order.totalAmount,
        shippingAddress: order.shippingAddress,
        items: order.items,
        createdAt: order.createdAt,
      },
    });
  } catch (err) {
    next(err);
  }
};

// ΓöÇΓöÇ GET /api/orders/my-orders ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const getMyOrders = async (req, res, next) => {
  try {
    const orders = await prisma.order.findMany({
      where: { userId: req.user.id },
      orderBy: { createdAt: 'desc' },
      include: {
        items: {
          include: {
            product: {
              select: { id: true, title: true, imageUrls: true, sku: true },
            },
          },
        },
      },
    });

    res.json({ data: orders });
  } catch (err) {
    next(err);
  }
};

module.exports = { createOrder, getMyOrders };

/**
 * @module controllers/productController.js
 * @description Handles product listing, retrieval, and creation.
 * Uses Prisma ORM for all database operations.
 *
 * Supported query params for GET /api/products:
 *   page      (default 1)                    ΓÇö page number
 *   limit     (default 12, max 50)           ΓÇö results per page
 *   category  (categoryId UUID)              ΓÇö filter by category ID
 *   size      (e.g. "M")                     ΓÇö filter by size (array contains)
 *   color     (e.g. "Black")                 ΓÇö filter by color (array contains)
 *   sort      (newest|price_asc|price_desc)  ΓÇö ordering
 *   search    (string)                       ΓÇö title/description text search
 */

'use strict';

const prisma = require('../prisma/client');
const ApiError = require('../utils/apiError');

// ΓöÇΓöÇ GET /api/products ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const getProducts = async (req, res, next) => {
  try {
    // --- Parse and sanitize query params ---
    const page = Math.max(1, parseInt(req.query.page, 10) || 1);
    const limit = Math.min(50, Math.max(1, parseInt(req.query.limit, 10) || 12));
    const skip = (page - 1) * limit;
    const { category, size, color, search } = req.query;
    const sort = req.query.sort || 'newest';

    // --- Build Prisma where clause ---
    const where = {};

    if (category) {
      where.categoryId = category;
    }
    // Prisma array filtering: check if the sizes/colors PostgreSQL array contains the value
    if (size) {
      where.sizes = { has: size };
    }
    if (color) {
      where.colors = { has: color };
    }
    if (search) {
      where.OR = [
        { title: { contains: search, mode: 'insensitive' } },
        { description: { contains: search, mode: 'insensitive' } },
      ];
    }

    // --- Determine orderBy ---
    const orderByMap = {
      newest:     { createdAt: 'desc' },
      price_asc:  { price: 'asc' },
      price_desc: { price: 'desc' },
    };
    const orderBy = orderByMap[sort] || orderByMap.newest;

    // --- Run count + data queries in parallel ---
    const [total, products] = await Promise.all([
      prisma.product.count({ where }),
      prisma.product.findMany({
        where,
        orderBy,
        skip,
        take: limit,
        include: {
          category: {
            select: { id: true, name: true, slug: true },
          },
        },
      }),
    ]);

    res.json({
      data: products,
      page,
      limit,
      total,
      totalPages: Math.ceil(total / limit),
    });
  } catch (err) {
    next(err);
  }
};

// ΓöÇΓöÇ GET /api/products/:id ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const getProduct = async (req, res, next) => {
  try {
    const { id } = req.params;

    const product = await prisma.product.findUnique({
      where: { id },
      include: {
        category: {
          select: { id: true, name: true, slug: true },
        },
      },
    });

    if (!product) throw new ApiError(404, `Product with id "${id}" not found.`);

    res.json({ data: product });
  } catch (err) {
    next(err);
  }
};

// ΓöÇΓöÇ POST /api/products ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Protected: Admin only (gated by authMiddleware + adminMiddleware in route)

const createProduct = async (req, res, next) => {
  try {
    const {
      title,
      description,
      price,
      sku,
      stockQuantity,
      sizes,
      colors,
      imageUrls,
      categoryId,
    } = req.body;

    // Validate required fields
    if (!title || price == null || !sku) {
      throw new ApiError(400, 'title, price, and sku are required.');
    }

    // Check SKU uniqueness (Prisma will also throw P2002 but this gives a cleaner message)
    const existing = await prisma.product.findUnique({
      where: { sku },
      select: { id: true },
    });
    if (existing) {
      throw new ApiError(409, `A product with SKU "${sku}" already exists.`);
    }

    const product = await prisma.product.create({
      data: {
        title,
        description: description || null,
        price: parseFloat(price),
        sku,
        stockQuantity: stockQuantity ?? 0,
        sizes: Array.isArray(sizes) ? sizes : [],
        colors: Array.isArray(colors) ? colors : [],
        imageUrls: Array.isArray(imageUrls) ? imageUrls : [],
        categoryId: categoryId || null,
      },
      include: {
        category: {
          select: { id: true, name: true, slug: true },
        },
      },
    });

    res.status(201).json({
      message: 'Product created successfully.',
      data: product,
    });
  } catch (err) {
    // Handle Prisma unique constraint violation gracefully
    if (err.code === 'P2002') {
      return next(new ApiError(409, `A product with that ${err.meta?.target} already exists.`));
    }
    next(err);
  }
};

// ΓöÇΓöÇ GET /api/products/:id/related ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const getRelatedProducts = async (req, res, next) => {
  try {
    const { id } = req.params;

    const product = await prisma.product.findUnique({
      where: { id },
      select: { categoryId: true },
    });
    if (!product) throw new ApiError(404, 'Product not found.');

    const related = await prisma.product.findMany({
      where: {
        categoryId: product.categoryId,
        id: { not: id },
      },
      take: 4,
      select: {
        id: true,
        title: true,
        price: true,
        imageUrls: true,
        sizes: true,
        colors: true,
        sku: true,
      },
    });

    res.json({ data: related });
  } catch (err) {
    next(err);
  }
};

module.exports = { getProducts, getProduct, createProduct, getRelatedProducts };

/**
 * @module db/index.js
 * @description Singleton pg.Pool connection to PostgreSQL.
 * All controllers import this pool and call pool.query().
 * Connection details come from the DATABASE_URL environment variable.
 */

const { Pool } = require('pg');

/**
 * @type {Pool}
 * @description A shared connection pool.
 * max: 10 connections ΓÇö suitable for a small-to-medium load.
 * idleTimeoutMillis: release idle connections after 30s.
 * connectionTimeoutMillis: fail fast if no connection available after 2s.
 */
const pool = new Pool({
    connectionString: process.env.DATABASE_URL,
    max: 10,
    idleTimeoutMillis: 30000,
    connectionTimeoutMillis: 2000,
    // In production, if using SSL (e.g. Heroku, Neon, Supabase), uncomment:
    // ssl: { rejectUnauthorized: false },
});

// Log a warning if the pool encounters a background error
pool.on('error', (err) => {
    console.error('[DB] Unexpected pool error:', err.message);
    // Do NOT process.exit here ΓÇö let the request-level error handler deal with it
});

module.exports = pool;

/**
 * @module middleware/auth.js
 * @description JWT authentication and admin authorization middleware.
 *
 * Usage:
 *   const { authMiddleware, adminMiddleware } = require('./middleware/auth');
 *   router.post('/orders', authMiddleware, orderController.createOrder);
 *   router.post('/products', authMiddleware, adminMiddleware, productController.createProduct);
 *
 * Authorization header format:
 *   Authorization: Bearer <jwt>
 *
 * On success: attaches `req.user = { id, email, role }` and calls `next()`.
 * On failure: forwards an ApiError(401 or 403) to the global error handler.
 */

'use strict';

const jwt = require('jsonwebtoken');
const ApiError = require('../utils/apiError');

// ΓöÇΓöÇ authMiddleware ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Verifies the JWT in the Authorization header.
 * Injects `req.user = { id, email, role }` on success.
 */
const authMiddleware = (req, _res, next) => {
  try {
    const authHeader = req.headers['authorization'];

    // Header must exist and start with "Bearer "
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      throw new ApiError(401, 'No token provided. Please log in.');
    }

    const token = authHeader.split(' ')[1];

    // Verify the token against JWT_SECRET
    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // Attach the decoded payload to req.user for downstream use
    req.user = {
      id: decoded.id,
      email: decoded.email,
      role: decoded.role,
    };

    next();
  } catch (err) {
    if (err instanceof ApiError) return next(err);
    next(new ApiError(401, 'Invalid or expired token. Please log in again.'));
  }
};

// ΓöÇΓöÇ adminMiddleware ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Requires the user to have the ADMIN role.
 * Must be chained AFTER authMiddleware.
 *
 * @example
 *   router.post('/products', authMiddleware, adminMiddleware, createProduct);
 */
const adminMiddleware = (req, _res, next) => {
  if (!req.user || req.user.role !== 'ADMIN') {
    return next(new ApiError(403, 'Forbidden. Admin access required.'));
  }
  next();
};

// Keep backwards-compatible aliases for any existing code referencing old names
const verifyToken = authMiddleware;
const requireAdmin = adminMiddleware;

module.exports = { authMiddleware, adminMiddleware, verifyToken, requireAdmin };

/**
 * @module prisma/client.js
 * @description Singleton Prisma Client instance.
 * Reuses a single connection in development to avoid exhausting the pool
 * during hot-reloads (nodemon), and creates a fresh instance in production.
 */

'use strict';

const { PrismaClient } = require('@prisma/client');

// Prevent multiple Prisma instances during hot-reload in development
const globalForPrisma = global;

const prisma =
  globalForPrisma.prisma ??
  new PrismaClient({
    log:
      process.env.NODE_ENV === 'development'
        ? ['query', 'error', 'warn']
        : ['error'],
  });

if (process.env.NODE_ENV !== 'production') {
  globalForPrisma.prisma = prisma;
}

module.exports = prisma;

/**
 * @module routes/auth.js
 * POST /api/auth/register  ΓÇö create a new customer account
 * POST /api/auth/login     ΓÇö authenticate and receive a JWT
 * GET  /api/auth/me        ΓÇö get current user's profile (protected)
 */

'use strict';

const express = require('express');
const { register, login, getMe } = require('../controllers/authController');
const { authMiddleware } = require('../middleware/auth');

const router = express.Router();

router.post('/register', register);
router.post('/login', login);
router.get('/me', authMiddleware, getMe);

module.exports = router;

/**
 * @module routes/orders.js
 * POST /api/orders           ΓÇö create order (protected: logged in users)
 * GET  /api/orders/my-orders ΓÇö get current user's orders (protected)
 */

'use strict';

const express = require('express');
const { createOrder, getMyOrders } = require('../controllers/orderController');
const { authMiddleware } = require('../middleware/auth');

const router = express.Router();

// Both routes require authentication
router.use(authMiddleware);

router.post('/', createOrder);
router.get('/my-orders', getMyOrders);

module.exports = router;

/**
 * @module routes/products.js
 * GET  /api/products           ΓÇö paginated list with filtering & sorting (public)
 * GET  /api/products/:id       ΓÇö single product with category (public)
 * GET  /api/products/:id/related ΓÇö related products (public)
 * POST /api/products           ΓÇö create product (Admin only)
 */

'use strict';

const express = require('express');
const {
  getProducts,
  getProduct,
  getRelatedProducts,
  createProduct,
} = require('../controllers/productController');
const { authMiddleware, adminMiddleware } = require('../middleware/auth');

const router = express.Router();

// Public routes
router.get('/', getProducts);
router.get('/:id/related', getRelatedProducts);
router.get('/:id', getProduct);

// Admin-protected route
router.post('/', authMiddleware, adminMiddleware, createProduct);

module.exports = router;

const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

async function main() {
  const categories = [
    { name: 'Women', slug: 'women' },
    { name: 'Men', slug: 'men' },
    { name: 'Children', slug: 'children' },
  ];

  console.log('Seeding categories...');

  for (const cat of categories) {
    const category = await prisma.category.upsert({
      where: { slug: cat.slug },
      update: {},
      create: {
        name: cat.name,
        slug: cat.slug,
      },
    });
    console.log(`- Created/Verified category: ${category.name} (${category.slug})`);
  }

  console.log('Categories seeded successfully!');
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
