"use client";

import { useState, useEffect } from "react";
import { useWishlistStore } from "@/store/useWishlistStore";
import { Heart } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import clsx from "clsx";

interface WishlistToggleProps {
    productId: string;
    className?: string;
}

export function WishlistToggle({ productId, className }: WishlistToggleProps) {
    const { toggleItem, items } = useWishlistStore();
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
    }, []);

    const isFavorite = mounted && items.includes(productId);

    if (!mounted) {
        return (
            <button className={clsx("flex items-center justify-center rounded-full bg-white/90 text-black opacity-50 cursor-wait", className)}>
                <Heart className="w-4 h-4" />
            </button>
        );
    }

    return (
        <button
            onClick={(e) => {
                e.preventDefault();
                e.stopPropagation();
                toggleItem(productId);
            }}
            className={clsx(
                "z-30 flex items-center justify-center rounded-full transition-all duration-300",
                isFavorite 
                    ? "bg-black text-white dark:bg-white dark:text-black scale-110 shadow-lg" 
                    : "bg-white/90 backdrop-blur-sm text-black hover:bg-black hover:text-white",
                className
            )}
        >
            <AnimatePresence mode="wait">
                <motion.div
                    key={isFavorite ? "active" : "inactive"}
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    exit={{ scale: 0.8, opacity: 0 }}
                    transition={{ duration: 0.2 }}
                >
                    <Heart 
                        className={clsx(
                            "w-4 h-4", 
                            isFavorite && "fill-current"
                        )} 
                    />
                </motion.div>
            </AnimatePresence>
        </button>
    );
}

